package com.example.oidc.config;

import com.example.oidc.service.CustomOidcUserService;
import com.example.oidc.handler.OidcAuthenticationSuccessHandler;
import com.example.oidc.handler.OidcAuthenticationFailureHandler;
import com.example.oidc.handler.OidcLogoutSuccessHandler;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.oauth2.client.registration.ClientRegistrationRepository;
import org.springframework.security.oauth2.client.web.DefaultOAuth2AuthorizationRequestResolver;
import org.springframework.security.oauth2.client.web.OAuth2AuthorizationRequestResolver;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.csrf.CookieCsrfTokenRepository;

@Configuration
@EnableWebSecurity
public class SecurityConfig {

    private final CustomOidcUserService customOidcUserService;
    private final OidcAuthenticationSuccessHandler successHandler;
    private final OidcAuthenticationFailureHandler failureHandler;
    private final OidcLogoutSuccessHandler logoutSuccessHandler;
    private final ClientRegistrationRepository clientRegistrationRepository;

    @Value("${oidc.session.timeout-minutes:60}")
    private int sessionTimeoutMinutes;

    public SecurityConfig(CustomOidcUserService customOidcUserService,
                          OidcAuthenticationSuccessHandler successHandler,
                          OidcAuthenticationFailureHandler failureHandler,
                          OidcLogoutSuccessHandler logoutSuccessHandler,
                          ClientRegistrationRepository clientRegistrationRepository) {
        this.customOidcUserService = customOidcUserService;
        this.successHandler = successHandler;
        this.failureHandler = failureHandler;
        this.logoutSuccessHandler = logoutSuccessHandler;
        this.clientRegistrationRepository = clientRegistrationRepository;
    }

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
            .authorizeHttpRequests(authz -> authz
                .requestMatchers("/", "/login", "/error", "/css/**", "/js/**", "/images/**", "/public/**").permitAll()
                .requestMatchers("/admin/**").hasRole("ADMIN")
                .anyRequest().authenticated()
            )
            .oauth2Login(oauth2 -> oauth2
                .authorizationEndpoint(authorization -> authorization
                    .authorizationRequestResolver(authorizationRequestResolver())
                )
                .tokenEndpoint(token -> token
                    .accessTokenResponseClient(new CustomAuthorizationCodeTokenResponseClient())
                )
                .userInfoEndpoint(userInfo -> userInfo
                    .oidcUserService(customOidcUserService)
                )
                .successHandler(successHandler)
                .failureHandler(failureHandler)
                .loginPage("/login")
            )
            .logout(logout -> logout
                .logoutUrl("/logout")
                .logoutSuccessHandler(logoutSuccessHandler)
                .invalidateHttpSession(true)
                .clearAuthentication(true)
                .deleteCookies("JSESSIONID")
            )
            .csrf(csrf -> csrf
                .csrfTokenRepository(CookieCsrfTokenRepository.withHttpOnlyFalse())
            )
            .sessionManagement(session -> session
                .maximumSessions(1)
                .expiredUrl("/login?expired")
            );

        return http.build();
    }

    private OAuth2AuthorizationRequestResolver authorizationRequestResolver() {
        DefaultOAuth2AuthorizationRequestResolver resolver =
            new DefaultOAuth2AuthorizationRequestResolver(
                clientRegistrationRepository, "/oauth2/authorization");
        resolver.setAuthorizationRequestCustomizer(customizer ->
            customizer.additionalParameters(params -> {
                params.put("prompt", "consent");
            })
        );
        return resolver;
    }
}

