package com.example.oidc.config;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.oauth2.client.endpoint.DefaultAuthorizationCodeTokenResponseClient;
import org.springframework.security.oauth2.client.endpoint.OAuth2AccessTokenResponseClient;
import org.springframework.security.oauth2.client.endpoint.OAuth2AuthorizationCodeGrantRequest;
import org.springframework.security.oauth2.core.endpoint.OAuth2AccessTokenResponse;

public class CustomAuthorizationCodeTokenResponseClient
        implements OAuth2AccessTokenResponseClient<OAuth2AuthorizationCodeGrantRequest> {

    private static final Logger logger = LoggerFactory.getLogger(CustomAuthorizationCodeTokenResponseClient.class);

    private final DefaultAuthorizationCodeTokenResponseClient delegate =
            new DefaultAuthorizationCodeTokenResponseClient();

    @Override
    public OAuth2AccessTokenResponse getTokenResponse(OAuth2AuthorizationCodeGrantRequest authorizationGrantRequest) {
        logger.info("Exchanging authorization code for tokens at token endpoint: {}",
                authorizationGrantRequest.getClientRegistration().getProviderDetails().getTokenUri());
        logger.debug("Authorization code grant request for client: {}",
                authorizationGrantRequest.getClientRegistration().getClientId());

        OAuth2AccessTokenResponse response = delegate.getTokenResponse(authorizationGrantRequest);

        logger.info("Successfully obtained tokens. Access token type: {}, Scopes: {}",
                response.getAccessToken().getTokenType().getValue(),
                response.getAccessToken().getScopes());

        if (response.getAdditionalParameters().containsKey("id_token")) {
            logger.debug("id_token is present in the token response");
        }

        return response;
    }
}

