package com.example.oidc.model;

import java.io.Serializable;
import java.time.Instant;
import java.util.Map;
import java.util.Set;

public class UserSession implements Serializable {

    private static final long serialVersionUID = 1L;

    private String sessionId;
    private String subject;
    private String email;
    private String name;
    private String preferredUsername;
    private String picture;
    private Set<String> roles;
    private Map<String, Object> claims;
    private String accessToken;
    private String refreshToken;
    private String idToken;
    private Instant accessTokenExpiresAt;
    private Instant sessionCreatedAt;
    private Instant lastAccessedAt;
    private String issuer;
    private String audience;

    public UserSession() {
        this.sessionCreatedAt = Instant.now();
        this.lastAccessedAt = Instant.now();
    }

    // Getters and Setters
    public String getSessionId() { return sessionId; }
    public void setSessionId(String sessionId) { this.sessionId = sessionId; }

    public String getSubject() { return subject; }
    public void setSubject(String subject) { this.subject = subject; }

    public String getEmail() { return email; }
    public void setEmail(String email) { this.email = email; }

    public String getName() { return name; }
    public void setName(String name) { this.name = name; }

    public String getPreferredUsername() { return preferredUsername; }
    public void setPreferredUsername(String preferredUsername) { this.preferredUsername = preferredUsername; }

    public String getPicture() { return picture; }
    public void setPicture(String picture) { this.picture = picture; }

    public Set<String> getRoles() { return roles; }
    public void setRoles(Set<String> roles) { this.roles = roles; }

    public Map<String, Object> getClaims() { return claims; }
    public void setClaims(Map<String, Object> claims) { this.claims = claims; }

    public String getAccessToken() { return accessToken; }
    public void setAccessToken(String accessToken) { this.accessToken = accessToken; }

    public String getRefreshToken() { return refreshToken; }
    public void setRefreshToken(String refreshToken) { this.refreshToken = refreshToken; }

    public String getIdToken() { return idToken; }
    public void setIdToken(String idToken) { this.idToken = idToken; }

    public Instant getAccessTokenExpiresAt() { return accessTokenExpiresAt; }
    public void setAccessTokenExpiresAt(Instant accessTokenExpiresAt) { this.accessTokenExpiresAt = accessTokenExpiresAt; }

    public Instant getSessionCreatedAt() { return sessionCreatedAt; }
    public void setSessionCreatedAt(Instant sessionCreatedAt) { this.sessionCreatedAt = sessionCreatedAt; }

    public Instant getLastAccessedAt() { return lastAccessedAt; }
    public void setLastAccessedAt(Instant lastAccessedAt) { this.lastAccessedAt = lastAccessedAt; }

    public String getIssuer() { return issuer; }
    public void setIssuer(String issuer) { this.issuer = issuer; }

    public String getAudience() { return audience; }
    public void setAudience(String audience) { this.audience = audience; }

    public boolean isAccessTokenExpired() {
        return accessTokenExpiresAt != null && Instant.now().isAfter(accessTokenExpiresAt);
    }

    @Override
    public String toString() {
        return "UserSession{" +
                "subject='" + subject + '\'' +
                ", email='" + email + '\'' +
                ", name='" + name + '\'' +
                ", roles=" + roles +
                ", sessionCreatedAt=" + sessionCreatedAt +
                '}';
    }
}

