package com.example.oidc.service;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.GrantedAuthority;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.oauth2.client.oidc.userinfo.OidcUserRequest;
import org.springframework.security.oauth2.client.oidc.userinfo.OidcUserService;
import org.springframework.security.oauth2.core.OAuth2AuthenticationException;
import org.springframework.security.oauth2.core.oidc.OidcIdToken;
import org.springframework.security.oauth2.core.oidc.user.DefaultOidcUser;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.stereotype.Service;

import java.util.*;
import java.util.stream.Collectors;

@Service
public class CustomOidcUserService extends OidcUserService {

    private static final Logger logger = LoggerFactory.getLogger(CustomOidcUserService.class);

    private final IdTokenClaimsParser idTokenClaimsParser;

    public CustomOidcUserService(IdTokenClaimsParser idTokenClaimsParser) {
        this.idTokenClaimsParser = idTokenClaimsParser;
    }

    @Override
    public OidcUser loadUser(OidcUserRequest userRequest) throws OAuth2AuthenticationException {
        OidcUser oidcUser = super.loadUser(userRequest);

        logger.info("Loading OIDC user: subject={}", oidcUser.getSubject());
        logger.debug("ID Token claims: {}", oidcUser.getIdToken().getClaims());
        logger.debug("UserInfo claims: {}", oidcUser.getUserInfo() != null ? oidcUser.getUserInfo().getClaims() : "N/A");

        // Parse id_token claims
        Map<String, Object> parsedClaims = idTokenClaimsParser.parseIdTokenClaims(oidcUser.getIdToken());
        logger.info("Parsed ID token claims for user: {}", parsedClaims.get("email"));

        // Extract roles from claims
        Set<GrantedAuthority> authorities = extractAuthorities(oidcUser);
        logger.debug("Extracted authorities: {}", authorities);

        // Create enhanced OIDC user with custom authorities
        return new DefaultOidcUser(
                authorities,
                oidcUser.getIdToken(),
                oidcUser.getUserInfo(),
                "sub"
        );
    }

    private Set<GrantedAuthority> extractAuthorities(OidcUser oidcUser) {
        Set<GrantedAuthority> authorities = new LinkedHashSet<>(oidcUser.getAuthorities());

        // Extract roles from id_token claims (common claim names)
        OidcIdToken idToken = oidcUser.getIdToken();

        // Check for "roles" claim
        Object rolesClaim = idToken.getClaim("roles");
        if (rolesClaim instanceof Collection<?>) {
            ((Collection<?>) rolesClaim).forEach(role ->
                authorities.add(new SimpleGrantedAuthority("ROLE_" + role.toString().toUpperCase()))
            );
        }

        // Check for "groups" claim
        Object groupsClaim = idToken.getClaim("groups");
        if (groupsClaim instanceof Collection<?>) {
            ((Collection<?>) groupsClaim).forEach(group ->
                authorities.add(new SimpleGrantedAuthority("ROLE_" + group.toString().toUpperCase()))
            );
        }

        // Check for realm_access.roles (Keycloak format)
        Object realmAccess = idToken.getClaim("realm_access");
        if (realmAccess instanceof Map) {
            Object realmRoles = ((Map<?, ?>) realmAccess).get("roles");
            if (realmRoles instanceof Collection<?>) {
                ((Collection<?>) realmRoles).forEach(role ->
                    authorities.add(new SimpleGrantedAuthority("ROLE_" + role.toString().toUpperCase()))
                );
            }
        }

        // Default role for all authenticated users
        authorities.add(new SimpleGrantedAuthority("ROLE_USER"));

        return authorities;
    }
}

