// ID Token Claims Parser
// ============================================================
package com.example.oidc.service;

import com.nimbusds.jwt.JWT;
import com.nimbusds.jwt.JWTClaimsSet;
import com.nimbusds.jwt.JWTParser;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.oauth2.core.oidc.OidcIdToken;
import org.springframework.stereotype.Component;

import java.text.ParseException;
import java.util.HashMap;
import java.util.Map;

@Component
public class IdTokenClaimsParser {

    private static final Logger logger = LoggerFactory.getLogger(IdTokenClaimsParser.class);

    public Map<String, Object> parseIdTokenClaims(OidcIdToken idToken) {
        Map<String, Object> parsedClaims = new HashMap<>();

        // Parse standard OIDC claims from the OidcIdToken object
        parsedClaims.put("subject", idToken.getSubject());
        parsedClaims.put("issuer", idToken.getIssuer() != null ? idToken.getIssuer().toString() : null);
        parsedClaims.put("audience", idToken.getAudience());
        parsedClaims.put("issuedAt", idToken.getIssuedAt());
        parsedClaims.put("expiresAt", idToken.getExpiresAt());
        parsedClaims.put("nonce", idToken.getNonce());
        parsedClaims.put("authTime", idToken.getAuthenticatedAt());
        parsedClaims.put("acr", idToken.getAuthenticationContextClass());
        parsedClaims.put("amr", idToken.getAuthenticationMethods());
        parsedClaims.put("azp", idToken.getAuthorizedParty());

        // Parse profile claims
        parsedClaims.put("email", idToken.getEmail());
        parsedClaims.put("emailVerified", idToken.getEmailVerified());
        parsedClaims.put("name", idToken.getFullName());
        parsedClaims.put("givenName", idToken.getGivenName());
        parsedClaims.put("familyName", idToken.getFamilyName());
        parsedClaims.put("preferredUsername", idToken.getPreferredUsername());
        parsedClaims.put("picture", idToken.getPicture());
        parsedClaims.put("locale", idToken.getLocale());
        parsedClaims.put("zoneInfo", idToken.getZoneInfo());

        // Also parse the raw JWT for any custom claims
        if (idToken.getTokenValue() != null) {
            try {
                JWT jwt = JWTParser.parse(idToken.getTokenValue());
                JWTClaimsSet claimsSet = jwt.getJWTClaimsSet();

                // Add all claims including custom ones
                Map<String, Object> allClaims = claimsSet.getClaims();
                allClaims.forEach((key, value) -> {
                    if (!parsedClaims.containsKey(key)) {
                        parsedClaims.put(key, value);
                        logger.debug("Found custom claim: {} = {}", key, value);
                    }
                });

                logger.info("JWT Algorithm: {}", jwt.getHeader().getAlgorithm());
                logger.info("JWT Key ID: {}", jwt.getHeader().getKeyID());

            } catch (ParseException e) {
                logger.error("Failed to parse id_token JWT", e);
            }
        }

        // Log parsed claims summary
        logger.info("Parsed ID token for subject: {}, email: {}, name: {}",
                parsedClaims.get("subject"),
                parsedClaims.get("email"),
                parsedClaims.get("name"));

        return parsedClaims;
    }

    public Map<String, Object> parseRawIdToken(String idTokenValue) {
        Map<String, Object> claims = new HashMap<>();
        try {
            JWT jwt = JWTParser.parse(idTokenValue);
            JWTClaimsSet claimsSet = jwt.getJWTClaimsSet();
            claims.putAll(claimsSet.getClaims());
        } catch (ParseException e) {
            logger.error("Failed to parse raw id_token", e);
        }
        return claims;
    }
}

