package com.example.oidc.service;

import com.example.oidc.model.UserSession;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.oauth2.client.OAuth2AuthorizedClient;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.stereotype.Service;

import java.time.Instant;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.stream.Collectors;

@Service
public class UserSessionService {

    private static final Logger logger = LoggerFactory.getLogger(UserSessionService.class);

    private final IdTokenClaimsParser idTokenClaimsParser;
    private final Map<String, UserSession> activeSessions = new ConcurrentHashMap<>();

    public UserSessionService(IdTokenClaimsParser idTokenClaimsParser) {
        this.idTokenClaimsParser = idTokenClaimsParser;
    }

    public UserSession createSession(OidcUser oidcUser, OAuth2AuthorizedClient authorizedClient) {
        UserSession session = new UserSession();

        String sessionId = UUID.randomUUID().toString();
        session.setSessionId(sessionId);

        // Parse id_token claims
        Map<String, Object> claims = idTokenClaimsParser.parseIdTokenClaims(oidcUser.getIdToken());
        session.setClaims(claims);

        // Set standard user info from id_token claims
        session.setSubject(oidcUser.getSubject());
        session.setEmail(oidcUser.getEmail());
        session.setName(oidcUser.getFullName());
        session.setPreferredUsername(oidcUser.getPreferredUsername());
        session.setPicture(oidcUser.getPicture());

        if (oidcUser.getIdToken().getIssuer() != null) {
            session.setIssuer(oidcUser.getIdToken().getIssuer().toString());
        }
        if (oidcUser.getIdToken().getAudience() != null && !oidcUser.getIdToken().getAudience().isEmpty()) {
            session.setAudience(String.join(",", oidcUser.getIdToken().getAudience()));
        }

        // Extract roles
        Set<String> roles = oidcUser.getAuthorities().stream()
                .map(auth -> auth.getAuthority())
                .filter(auth -> auth.startsWith("ROLE_"))
                .map(auth -> auth.substring(5))
                .collect(Collectors.toSet());
        session.setRoles(roles);

        // Store tokens
        if (authorizedClient != null) {
            session.setAccessToken(authorizedClient.getAccessToken().getTokenValue());
            session.setAccessTokenExpiresAt(authorizedClient.getAccessToken().getExpiresAt());

            if (authorizedClient.getRefreshToken() != null) {
                session.setRefreshToken(authorizedClient.getRefreshToken().getTokenValue());
            }
        }

        session.setIdToken(oidcUser.getIdToken().getTokenValue());
        session.setSessionCreatedAt(Instant.now());
        session.setLastAccessedAt(Instant.now());

        // Store session
        activeSessions.put(sessionId, session);

        logger.info("Created user session: sessionId={}, subject={}, email={}, roles={}",
                sessionId, session.getSubject(), session.getEmail(), session.getRoles());

        return session;
    }

    public Optional<UserSession> getSession(String sessionId) {
        UserSession session = activeSessions.get(sessionId);
        if (session != null) {
            session.setLastAccessedAt(Instant.now());
        }
        return Optional.ofNullable(session);
    }

    public void invalidateSession(String sessionId) {
        UserSession removed = activeSessions.remove(sessionId);
        if (removed != null) {
            logger.info("Invalidated session: sessionId={}, subject={}", sessionId, removed.getSubject());
        }
    }

    public void invalidateSessionBySubject(String subject) {
        activeSessions.entrySet().removeIf(entry -> {
            if (entry.getValue().getSubject().equals(subject)) {
                logger.info("Invalidated session for subject: {}", subject);
                return true;
            }
            return false;
        });
    }

    public List<UserSession> getActiveSessionsForSubject(String subject) {
        return activeSessions.values().stream()
                .filter(session -> session.getSubject().equals(subject))
                .collect(Collectors.toList());
    }

    public int getActiveSessionCount() {
        return activeSessions.size();
    }
}

