package com.example.oidc.service;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.oauth2.client.OAuth2AuthorizedClient;
import org.springframework.security.oauth2.client.OAuth2AuthorizedClientService;
import org.springframework.security.oauth2.client.authentication.OAuth2AuthenticationToken;
import org.springframework.security.oauth2.client.registration.ClientRegistration;
import org.springframework.security.oauth2.client.registration.ClientRegistrationRepository;
import org.springframework.security.oauth2.core.OAuth2AccessToken;
import org.springframework.security.oauth2.core.OAuth2RefreshToken;
import org.springframework.stereotype.Service;
import org.springframework.http.*;
import org.springframework.util.LinkedMultiValueMap;
import org.springframework.util.MultiValueMap;
import org.springframework.web.client.RestTemplate;

import java.time.Instant;
import java.util.Map;

@Service
public class TokenRefreshService {

    private static final Logger logger = LoggerFactory.getLogger(TokenRefreshService.class);

    private final ClientRegistrationRepository clientRegistrationRepository;
    private final OAuth2AuthorizedClientService authorizedClientService;
    private final RestTemplate restTemplate;

    public TokenRefreshService(ClientRegistrationRepository clientRegistrationRepository,
                                OAuth2AuthorizedClientService authorizedClientService) {
        this.clientRegistrationRepository = clientRegistrationRepository;
        this.authorizedClientService = authorizedClientService;
        this.restTemplate = new RestTemplate();
    }

    @SuppressWarnings("unchecked")
    public OAuth2AuthorizedClient refreshToken(OAuth2AuthenticationToken authentication) {
        String registrationId = authentication.getAuthorizedClientRegistrationId();
        OAuth2AuthorizedClient currentClient = authorizedClientService.loadAuthorizedClient(
                registrationId, authentication.getName());

        if (currentClient == null || currentClient.getRefreshToken() == null) {
            logger.warn("No refresh token available for user: {}", authentication.getName());
            return null;
        }

        // Check if access token is still valid
        if (currentClient.getAccessToken().getExpiresAt() != null &&
                currentClient.getAccessToken().getExpiresAt().isAfter(Instant.now())) {
            return currentClient;
        }

        ClientRegistration clientRegistration = clientRegistrationRepository.findByRegistrationId(registrationId);
        String tokenUri = clientRegistration.getProviderDetails().getTokenUri();

        logger.info("Refreshing access token at: {}", tokenUri);

        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);
        headers.setBasicAuth(clientRegistration.getClientId(), clientRegistration.getClientSecret());

        MultiValueMap<String, String> body = new LinkedMultiValueMap<>();
        body.add("grant_type", "refresh_token");
        body.add("refresh_token", currentClient.getRefreshToken().getTokenValue());

        try {
            ResponseEntity<Map> response = restTemplate.exchange(
                    tokenUri, HttpMethod.POST, new HttpEntity<>(body, headers), Map.class);

            Map<String, Object> tokenResponse = response.getBody();
            if (tokenResponse != null) {
                String newAccessTokenValue = (String) tokenResponse.get("access_token");
                Integer expiresIn = (Integer) tokenResponse.get("expires_in");
                String newRefreshTokenValue = tokenResponse.containsKey("refresh_token") ?
                        (String) tokenResponse.get("refresh_token") :
                        currentClient.getRefreshToken().getTokenValue();

                OAuth2AccessToken newAccessToken = new OAuth2AccessToken(
                        OAuth2AccessToken.TokenType.BEARER,
                        newAccessTokenValue,
                        Instant.now(),
                        Instant.now().plusSeconds(expiresIn != null ? expiresIn : 3600)
                );

                OAuth2RefreshToken newRefreshToken = new OAuth2RefreshToken(
                        newRefreshTokenValue, Instant.now());

                OAuth2AuthorizedClient newClient = new OAuth2AuthorizedClient(
                        clientRegistration, authentication.getName(),
                        newAccessToken, newRefreshToken);

                authorizedClientService.saveAuthorizedClient(newClient, authentication);

                logger.info("Successfully refreshed access token for user: {}", authentication.getName());
                return newClient;
            }
        } catch (Exception e) {
            logger.error("Failed to refresh token for user: {}", authentication.getName(), e);
        }

        return null;
    }
}

