package com.example.oidc.handler;

import com.example.oidc.model.UserSession;
import com.example.oidc.service.UserSessionService;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.security.core.Authentication;
import org.springframework.security.oauth2.client.OAuth2AuthorizedClient;
import org.springframework.security.oauth2.client.OAuth2AuthorizedClientService;
import org.springframework.security.oauth2.client.authentication.OAuth2AuthenticationToken;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.security.web.authentication.AuthenticationSuccessHandler;
import org.springframework.stereotype.Component;

import java.io.IOException;

@Component
public class OidcAuthenticationSuccessHandler implements AuthenticationSuccessHandler {

    private static final Logger logger = LoggerFactory.getLogger(OidcAuthenticationSuccessHandler.class);

    private final UserSessionService userSessionService;
    private final OAuth2AuthorizedClientService authorizedClientService;

    @Value("${oidc.post-login-redirect:/dashboard}")
    private String postLoginRedirect;

    @Value("${oidc.session.timeout-minutes:60}")
    private int sessionTimeoutMinutes;

    public OidcAuthenticationSuccessHandler(UserSessionService userSessionService,
                                             OAuth2AuthorizedClientService authorizedClientService) {
        this.userSessionService = userSessionService;
        this.authorizedClientService = authorizedClientService;
    }

    @Override
    public void onAuthenticationSuccess(HttpServletRequest request, HttpServletResponse response,
                                         Authentication authentication) throws IOException, ServletException {
        OAuth2AuthenticationToken oauthToken = (OAuth2AuthenticationToken) authentication;
        OidcUser oidcUser = (OidcUser) oauthToken.getPrincipal();

        logger.info("OIDC authentication successful for user: {}", oidcUser.getSubject());

        // Get the authorized client with tokens
        OAuth2AuthorizedClient authorizedClient = authorizedClientService.loadAuthorizedClient(
                oauthToken.getAuthorizedClientRegistrationId(),
                oauthToken.getName()
        );

        // Create user session from id_token claims
        UserSession userSession = userSessionService.createSession(oidcUser, authorizedClient);

        // Store session info in HTTP session
        HttpSession httpSession = request.getSession(true);
        httpSession.setAttribute("USER_SESSION", userSession);
        httpSession.setAttribute("USER_SESSION_ID", userSession.getSessionId());
        httpSession.setMaxInactiveInterval(sessionTimeoutMinutes * 60);

        logger.info("User session created: sessionId={}, email={}, redirecting to {}",
                userSession.getSessionId(), userSession.getEmail(), postLoginRedirect);

        response.sendRedirect(postLoginRedirect);
    }
}

