package com.example.oidc.handler;

import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.AuthenticationException;
import org.springframework.security.web.authentication.AuthenticationFailureHandler;
import org.springframework.stereotype.Component;

import java.io.IOException;

@Component
public class OidcAuthenticationFailureHandler implements AuthenticationFailureHandler {

    private static final Logger logger = LoggerFactory.getLogger(OidcAuthenticationFailureHandler.class);

    @Override
    public void onAuthenticationFailure(HttpServletRequest request, HttpServletResponse response,
                                         AuthenticationException exception) throws IOException, ServletException {
        logger.error("OIDC authentication failed: {}", exception.getMessage(), exception);
        response.sendRedirect("/login?error=" + exception.getMessage());
    }
}

// ============================================================
// Logout Success Handler
// ============================================================
package com.example.oidc.handler;

import com.example.oidc.model.UserSession;
import com.example.oidc.service.UserSessionService;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.security.core.Authentication;
import org.springframework.security.oauth2.client.registration.ClientRegistration;
import org.springframework.security.oauth2.client.registration.ClientRegistrationRepository;
import org.springframework.security.web.authentication.logout.LogoutSuccessHandler;
import org.springframework.stereotype.Component;
import org.springframework.web.util.UriComponentsBuilder;

import java.io.IOException;

@Component
public class OidcLogoutSuccessHandler implements LogoutSuccessHandler {

    private static final Logger logger = LoggerFactory.getLogger(OidcLogoutSuccessHandler.class);

    private final UserSessionService userSessionService;
    private final ClientRegistrationRepository clientRegistrationRepository;

    @Value("${oidc.post-logout-redirect:/}")
    private String postLogoutRedirect;

    public OidcLogoutSuccessHandler(UserSessionService userSessionService,
                                     ClientRegistrationRepository clientRegistrationRepository) {
        this.userSessionService = userSessionService;
        this.clientRegistrationRepository = clientRegistrationRepository;
    }

    @Override
    public void onLogoutSuccess(HttpServletRequest request, HttpServletResponse response,
                                 Authentication authentication) throws IOException, ServletException {
        HttpSession httpSession = request.getSession(false);
        if (httpSession != null) {
            UserSession userSession = (UserSession) httpSession.getAttribute("USER_SESSION");
            if (userSession != null) {
                userSessionService.invalidateSession(userSession.getSessionId());
                logger.info("User session invalidated on logout: {}", userSession.getSessionId());
            }
        }

        // Try to perform RP-Initiated Logout if the provider supports it
        String endSessionEndpoint = getEndSessionEndpoint();
        if (endSessionEndpoint != null && authentication != null) {
            UserSession userSession = httpSession != null ?
                    (UserSession) httpSession.getAttribute("USER_SESSION") : null;

            String logoutUrl = UriComponentsBuilder.fromUriString(endSessionEndpoint)
                    .queryParam("post_logout_redirect_uri",
                            request.getScheme() + "://" + request.getServerName() + ":" +
                                    request.getServerPort() + postLogoutRedirect)
                    .queryParam("id_token_hint",
                            userSession != null ? userSession.getIdToken() : "")
                    .build().toUriString();

            logger.info("Redirecting to OIDC provider logout: {}", endSessionEndpoint);
            response.sendRedirect(logoutUrl);
        } else {
            response.sendRedirect(postLogoutRedirect);
        }
    }

    private String getEndSessionEndpoint() {
        try {
            ClientRegistration registration = clientRegistrationRepository.findByRegistrationId("oidc-provider");
            if (registration != null) {
                Object endSessionEndpoint = registration.getProviderDetails()
                        .getConfigurationMetadata().get("end_session_endpoint");
                return endSessionEndpoint != null ? endSessionEndpoint.toString() : null;
            }
        } catch (Exception e) {
            logger.debug("End session endpoint not available");
        }
        return null;
    }
}

