package com.example.oidc.controller;

import com.example.oidc.model.UserSession;
import com.example.oidc.service.TokenRefreshService;
import com.example.oidc.service.UserSessionService;
import jakarta.servlet.http.HttpSession;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.oauth2.client.authentication.OAuth2AuthenticationToken;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;

@Controller
public class DashboardController {

    private static final Logger logger = LoggerFactory.getLogger(DashboardController.class);

    private final UserSessionService userSessionService;
    private final TokenRefreshService tokenRefreshService;

    public DashboardController(UserSessionService userSessionService,
                                TokenRefreshService tokenRefreshService) {
        this.userSessionService = userSessionService;
        this.tokenRefreshService = tokenRefreshService;
    }

    @GetMapping("/dashboard")
    public String dashboard(@AuthenticationPrincipal OidcUser oidcUser,
                             HttpSession httpSession, Model model) {
        UserSession userSession = (UserSession) httpSession.getAttribute("USER_SESSION");

        if (userSession != null) {
            model.addAttribute("userSession", userSession);
            model.addAttribute("claims", userSession.getClaims());

            logger.debug("Dashboard accessed by: {}", userSession.getEmail());

            // Check if token needs refresh
            if (userSession.isAccessTokenExpired()) {
                logger.info("Access token expired for user: {}", userSession.getEmail());
                model.addAttribute("tokenExpired", true);
            }
        }

        if (oidcUser != null) {
            model.addAttribute("oidcUser", oidcUser);
            model.addAttribute("idTokenClaims", oidcUser.getIdToken().getClaims());
            model.addAttribute("userInfoClaims",
                    oidcUser.getUserInfo() != null ? oidcUser.getUserInfo().getClaims() : null);
        }

        return "dashboard";
    }

    @GetMapping("/profile")
    public String profile(@AuthenticationPrincipal OidcUser oidcUser, Model model) {
        if (oidcUser != null) {
            model.addAttribute("name", oidcUser.getFullName());
            model.addAttribute("email", oidcUser.getEmail());
            model.addAttribute("picture", oidcUser.getPicture());
            model.addAttribute("subject", oidcUser.getSubject());
            model.addAttribute("issuer", oidcUser.getIssuer());
            model.addAttribute("allClaims", oidcUser.getClaims());
        }
        return "profile";
    }

    @GetMapping("/refresh-token")
    public String refreshToken(OAuth2AuthenticationToken authentication, HttpSession httpSession) {
        tokenRefreshService.refreshToken(authentication);
        return "redirect:/dashboard";
    }
}

