package com.example.oidc.controller;

import com.example.oidc.model.UserSession;
import com.example.oidc.service.UserSessionService;
import jakarta.servlet.http.HttpSession;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.HashMap;
import java.util.Map;

@RestController
@RequestMapping("/api")
public class SessionApiController {

    private final UserSessionService userSessionService;

    public SessionApiController(UserSessionService userSessionService) {
        this.userSessionService = userSessionService;
    }

    @GetMapping("/session")
    public ResponseEntity<Map<String, Object>> getSessionInfo(
            @AuthenticationPrincipal OidcUser oidcUser, HttpSession httpSession) {
        Map<String, Object> sessionInfo = new HashMap<>();

        UserSession userSession = (UserSession) httpSession.getAttribute("USER_SESSION");
        if (userSession != null) {
            sessionInfo.put("sessionId", userSession.getSessionId());
            sessionInfo.put("subject", userSession.getSubject());
            sessionInfo.put("email", userSession.getEmail());
            sessionInfo.put("name", userSession.getName());
            sessionInfo.put("roles", userSession.getRoles());
            sessionInfo.put("issuer", userSession.getIssuer());
            sessionInfo.put("sessionCreatedAt", userSession.getSessionCreatedAt());
            sessionInfo.put("lastAccessedAt", userSession.getLastAccessedAt());
            sessionInfo.put("accessTokenExpired", userSession.isAccessTokenExpired());
        }

        if (oidcUser != null) {
            sessionInfo.put("idTokenClaims", oidcUser.getIdToken().getClaims());
        }

        sessionInfo.put("activeSessionCount", userSessionService.getActiveSessionCount());

        return ResponseEntity.ok(sessionInfo);
    }

    @GetMapping("/userinfo")
    public ResponseEntity<Map<String, Object>> getUserInfo(@AuthenticationPrincipal OidcUser oidcUser) {
        Map<String, Object> userInfo = new HashMap<>();

        if (oidcUser != null) {
            userInfo.put("subject", oidcUser.getSubject());
            userInfo.put("email", oidcUser.getEmail());
            userInfo.put("emailVerified", oidcUser.getEmailVerified());
            userInfo.put("name", oidcUser.getFullName());
            userInfo.put("givenName", oidcUser.getGivenName());
            userInfo.put("familyName", oidcUser.getFamilyName());
            userInfo.put("preferredUsername", oidcUser.getPreferredUsername());
            userInfo.put("picture", oidcUser.getPicture());
            userInfo.put("locale", oidcUser.getLocale());
            userInfo.put("authorities", oidcUser.getAuthorities());

            if (oidcUser.getUserInfo() != null) {
                userInfo.put("userInfoClaims", oidcUser.getUserInfo().getClaims());
            }
        }

        return ResponseEntity.ok(userInfo);
    }
}

