package com.example.oidc.config;

import com.example.oidc.service.UserSessionService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.scheduling.annotation.EnableScheduling;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Component;

@Component
@EnableScheduling
public class SessionCleanupScheduler {

    private static final Logger logger = LoggerFactory.getLogger(SessionCleanupScheduler.class);

    private final UserSessionService userSessionService;

    public SessionCleanupScheduler(UserSessionService userSessionService) {
        this.userSessionService = userSessionService;
    }

    @Scheduled(fixedRate = 300000) // Every 5 minutes
    public void logActiveSessionCount() {
        int count = userSessionService.getActiveSessionCount();
        logger.info("Active OIDC sessions: {}", count);
    }
}